import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';
import Modal from '../components/Modal';
import Sidebar from '../components/Sidebar';
import { Toaster, toast } from 'react-hot-toast';
import { FaBuilding, FaUserTie, FaUsers, FaChartLine, FaTrash, FaEdit, FaEye } from 'react-icons/fa';
import './Dashboard.css';

function Dashboard() {
    const { user, logout } = useAuth();
    const [stats, setStats] = useState({
        total_companies: 0,
        total_supervisors: 0,
        total_workers: 0,
        today_attendance: 0
    });
    const [companies, setCompanies] = useState([]);
    const [supervisors, setSupervisors] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('overview');

    // Modal states
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalType, setModalType] = useState(''); // 'company', 'supervisor'
    const [formData, setFormData] = useState({});

    useEffect(() => {
        fetchInitialData();
    }, []);

    const fetchInitialData = async () => {
        try {
            setLoading(true);
            const [statsRes, companiesRes, supervisorsRes] = await Promise.all([
                api.get('/super-admin/stats'),
                api.get('/super-admin/companies'),
                api.get('/super-admin/supervisors')
            ]);
            setStats(statsRes.data);
            setCompanies(companiesRes.data);
            setSupervisors(supervisorsRes.data);
        } catch (error) {
            console.error('Data fetch error:', error);
            toast.error('Failed to load dashboard data');
        } finally {
            setLoading(false);
        }
    };

    const handleLogout = async () => {
        await logout();
        window.location.href = '/login';
    };

    const handleCreateCompany = async (e) => {
        e.preventDefault();
        try {
            await api.post('/super-admin/companies', formData);
            toast.success('Company created successfully');
            setIsModalOpen(false);
            fetchInitialData();
        } catch (error) {
            toast.error(error.response?.data?.message || 'Error creating company');
        }
    };

    const handleCreateSupervisor = async (e) => {
        e.preventDefault();
        try {
            await api.post('/super-admin/supervisors', formData);
            toast.success('Supervisor created successfully');
            setIsModalOpen(false);
            fetchInitialData();
        } catch (error) {
            toast.error(error.response?.data?.message || 'Error creating supervisor');
        }
    };

    if (loading) return <div className="loading-screen">Loading buildPro...</div>;

    return (
        <div className="dashboard-layout">
            <Toaster position="top-right" />
            <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} />

            <div className="dashboard-main">
                <header className="dashboard-header">
                    <div className="header-left">
                        <h1>Super Admin Dashboard</h1>
                        <p>Welcome back, <strong>{user?.name}</strong></p>
                    </div>
                    <div className="header-right">
                        <span className="date-display">{new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}</span>
                    </div>
                </header>

                <div className="dashboard-content">
                    {activeTab === 'overview' && (
                        <>
                            <div className="stats-grid">
                                <div className="stat-card">
                                    <div className="stat-icon"><FaBuilding /></div>
                                    <div className="stat-info">
                                        <h3>{stats.total_companies}</h3>
                                        <p>Companies</p>
                                    </div>
                                </div>
                                <div className="stat-card">
                                    <div className="stat-icon"><FaUserTie /></div>
                                    <div className="stat-info">
                                        <h3>{stats.total_supervisors}</h3>
                                        <p>Supervisors</p>
                                    </div>
                                </div>
                                <div className="stat-card">
                                    <div className="stat-icon"><FaUsers /></div>
                                    <div className="stat-info">
                                        <h3>{stats.total_workers}</h3>
                                        <p>Workers</p>
                                    </div>
                                </div>
                                <div className="stat-card">
                                    <div className="stat-icon"><FaChartLine /></div>
                                    <div className="stat-info">
                                        <h3>{stats.today_attendance}</h3>
                                        <p>Today Present</p>
                                    </div>
                                </div>
                            </div>

                            <div className="quick-actions">
                                <button className="action-btn" onClick={() => { setModalType('company'); setFormData({}); setIsModalOpen(true); }}>
                                    + Add New Company
                                </button>
                                <button className="action-btn secondary" onClick={() => { setModalType('supervisor'); setFormData({}); setIsModalOpen(true); }}>
                                    + Register Supervisor
                                </button>
                            </div>
                        </>
                    )}

                    {activeTab === 'companies' && (
                        <div className="section-container">
                            <div className="section-header">
                                <h2>Management: Companies</h2>
                                <button onClick={() => { setModalType('company'); setFormData({}); setIsModalOpen(true); }}>Add Company</button>
                            </div>
                            <div className="data-table-wrapper">
                                <table className="data-table">
                                    <thead>
                                        <tr>
                                            <th>Company Name</th>
                                            <th>Location</th>
                                            <th>Supervisors</th>
                                            <th>Workers</th>
                                            <th>Actions</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {companies.map(company => (
                                            <tr key={company.id}>
                                                <td><strong>{company.name}</strong></td>
                                                <td>{company.location || 'N/A'}</td>
                                                <td>{company.users_count || 0}</td>
                                                <td>{company.workers_count || 0}</td>
                                                <td>
                                                    <div className="table-actions">
                                                        <button className="icon-btn edit"><FaEdit /></button>
                                                        <button className="icon-btn delete"><FaTrash /></button>
                                                    </div>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    )}

                    {activeTab === 'supervisors' && (
                        <div className="section-container">
                            <div className="section-header">
                                <h2>Management: Supervisors</h2>
                                <button onClick={() => { setModalType('supervisor'); setFormData({}); setIsModalOpen(true); }}>Add Supervisor</button>
                            </div>
                            <div className="data-table-wrapper">
                                <table className="data-table">
                                    <thead>
                                        <tr>
                                            <th>Name</th>
                                            <th>Email</th>
                                            <th>Assigned Company</th>
                                            <th>Actions</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {supervisors.map(sv => (
                                            <tr key={sv.id}>
                                                <td>{sv.name}</td>
                                                <td>{sv.email}</td>
                                                <td><span className="badge">{sv.company?.name || 'Unassigned'}</span></td>
                                                <td>
                                                    <div className="table-actions">
                                                        <button className="icon-btn edit"><FaEdit /></button>
                                                        <button className="icon-btn delete"><FaTrash /></button>
                                                    </div>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Modals */}
            <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={modalType === 'company' ? 'Add New Company' : 'Register Supervisor'}>
                {modalType === 'company' ? (
                    <form onSubmit={handleCreateCompany} className="modal-form">
                        <div className="form-group">
                            <label>Company Name</label>
                            <input type="text" required onChange={(e) => setFormData({ ...formData, name: e.target.value })} />
                        </div>
                        <div className="form-group">
                            <label>Location</label>
                            <input type="text" onChange={(e) => setFormData({ ...formData, location: e.target.value })} />
                        </div>
                        <div className="form-group">
                            <label>Phone</label>
                            <input type="text" onChange={(e) => setFormData({ ...formData, phone: e.target.value })} />
                        </div>
                        <button type="submit" className="submit-btn">Create Company</button>
                    </form>
                ) : (
                    <form onSubmit={handleCreateSupervisor} className="modal-form">
                        <div className="form-group">
                            <label>Full Name</label>
                            <input type="text" required onChange={(e) => setFormData({ ...formData, name: e.target.value })} />
                        </div>
                        <div className="form-group">
                            <label>Email Address</label>
                            <input type="email" required onChange={(e) => setFormData({ ...formData, email: e.target.value })} />
                        </div>
                        <div className="form-group">
                            <label>Password</label>
                            <input type="password" required onChange={(e) => setFormData({ ...formData, password: e.target.value })} />
                        </div>
                        <div className="form-group">
                            <label>Assign Company</label>
                            <select required onChange={(e) => setFormData({ ...formData, company_id: e.target.value })}>
                                <option value="">Select Company</option>
                                {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                            </select>
                        </div>
                        <button type="submit" className="submit-btn">Register Supervisor</button>
                    </form>
                )}
            </Modal>
        </div>
    );
}

export default Dashboard;
